  1550→bool FilterManager::createFilterChain() {
  1551→  if (state_.created_filter_chain_) {
  1552→    return false;
  1553→  }
  1554→  bool upgrade_rejected = false;
  1555→  const HeaderEntry* upgrade = nullptr;
  1556→  if (filter_manager_callbacks_.requestHeaders()) {
  1557→    upgrade = filter_manager_callbacks_.requestHeaders()->Upgrade();
  1558→
  1559→    // Treat CONNECT requests as a special upgrade case.
  1560→    if (!upgrade && HeaderUtility::isConnect(*filter_manager_callbacks_.requestHeaders())) {
  1561→      upgrade = filter_manager_callbacks_.requestHeaders()->Method();
  1562→    }
  1563→  }
  1564→
  1565→  state_.created_filter_chain_ = true;
  1566→  if (upgrade != nullptr) {
  1567→    const Router::RouteEntry::UpgradeMap* upgrade_map = filter_manager_callbacks_.upgradeMap();
  1568→
  1569→    if (filter_chain_factory_.createUpgradeFilterChain(upgrade->value().getStringView(),
  1570→                                                       upgrade_map, *this)) {
  1571→      filter_manager_callbacks_.upgradeFilterChainCreated();
  1572→      return true;
  1573→    } else {
  1574→      upgrade_rejected = true;
  1575→      // Fall through to the default filter chain. The function calling this
  1576→      // will send a local reply indicating that the upgrade failed.
  1577→    }
  1578→  }
  1579→
  1580→  // This filter chain options is only used for the downstream HTTP filter chains for now. So, try
  1581→  // to set valid initial route only when the downstream callbacks is available.
  1582→  FilterChainOptionsImpl options(
  1583→      filter_manager_callbacks_.downstreamCallbacks().has_value() ? streamInfo().route() : nullptr);
  1584→  filter_chain_factory_.createFilterChain(*this, false, options);
  1585→  return !upgrade_rejected;
  1586→}
